from marshmallow import Schema, fields, validates, ValidationError


class Bar(Schema):
    value = fields.String(required=True)

    @validates('value')
    def validate_value(self, value):
        if value == 'invalid':
            raise ValidationError('Value cannot be "invalid"')
        return value


class Foo(Schema):
    bar = fields.Nested(Bar)


sch = Foo()

print("Test 1: Nested field with validator that raises ValidationError")
try:
    result = sch.validate({
        'bar': {'value': 'invalid'},
    })
    print(f"Result: {result}")
except Exception as e:
    print(f"Error: {type(e).__name__}: {e}")

print("\nTest 2: Empty dict for nested field (missing required field)")
try:
    result = sch.validate({
        'bar': {},
    })
    print(f"Result: {result}")
except Exception as e:
    print(f"Error: {type(e).__name__}: {e}")

print("\nTest 3: None for nested field")
try:
    result = sch.validate({
        'bar': None,
    })
    print(f"Result: {result}")
except Exception as e:
    print(f"Error: {type(e).__name__}: {e}")

print("\nTest 4: List for nested field (with many=True)")
class FooMany(Schema):
    bars = fields.Nested(Bar, many=True)

sch_many = FooMany()

try:
    result = sch_many.validate({
        'bars': [{'value': 'valid'}, {'value': 'invalid'}],
    })
    print(f"Result: {result}")
except Exception as e:
    print(f"Error: {type(e).__name__}: {e}")

print("\nTest 5: Invalid list item for nested field (with many=True)")
try:
    result = sch_many.validate({
        'bars': [{'value': 'valid'}, 'not-a-dict'],
    })
    print(f"Result: {result}")
except Exception as e:
    print(f"Error: {type(e).__name__}: {e}")

print("\nTest 6: Schema with multiple nested fields")
class Baz(Schema):
    num = fields.Integer()

class ComplexSchema(Schema):
    bar = fields.Nested(Bar)
    baz = fields.Nested(Baz)

    @validates('baz')
    def validate_baz(self, value):
        print(f"Validating baz: {value}")
        return value

complex_sch = ComplexSchema()

try:
    result = complex_sch.validate({
        'bar': 'invalid',
        'baz': {'num': 42},
    })
    print(f"Result: {result}")
except Exception as e:
    print(f"Error: {type(e).__name__}: {e}")
EOF"}

